const PROOF_DIM: usize = 1024;
const PROOF_TRIALS: usize = 100;
const SIMILARITY_EPSILON: f64 = 0.05;
const PHI: f64 = 1.618033988749895;
const PHI_SQ: f64 = 2.618033988749895;

