// SEEDED RNG (simple LCG)
// ═══════════════════════════════════════════════════════════════════════════════

struct SeededRng {
    state: u64,
}

impl SeededRng {
    fn new(seed: u64) -> Self {
        Self { state: seed }
    }

    fn next(&mut self) -> u64 {
        self.state = self.state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
        self.state
    }

    fn trit(&mut self) -> i8 {
        (self.next() % 3) as i8 - 1
    }
}

