fn random_vector(dim: usize, seed: u64) -> TernaryVector {
    let mut rng = SeededRng::new(seed);
    let data: Vec<i8> = (0..dim).map(|_| rng.trit()).collect();
    TernaryVector { dimension: dim, data }
}

fn bind(a: &TernaryVector, b: &TernaryVector) -> TernaryVector {
    let data: Vec<i8> = a.data.iter().zip(&b.data).map(|(&x, &y)| x * y).collect();
    TernaryVector { dimension: a.dimension, data }
}

fn unbind(bound: &TernaryVector, key: &TernaryVector) -> TernaryVector {
    bind(bound, key)
}

fn bundle3(a: &TernaryVector, b: &TernaryVector, c: &TernaryVector) -> TernaryVector {
    let data: Vec<i8> = (0..a.dimension)
        .map(|i| {
            let s = a.data[i] as i16 + b.data[i] as i16 + c.data[i] as i16;
            if s > 0 { 1 } else if s < 0 { -1 } else { 0 }
        })
        .collect();
    TernaryVector { dimension: a.dimension, data }
}

fn cosine_similarity(a: &TernaryVector, b: &TernaryVector) -> f64 {
    let dot: f64 = a.data.iter().zip(&b.data).map(|(&x, &y)| (x as f64) * (y as f64)).sum();
    let norm_a: f64 = a.data.iter().map(|&x| (x as f64) * (x as f64)).sum::<f64>().sqrt();
    let norm_b: f64 = b.data.iter().map(|&x| (x as f64) * (x as f64)).sum::<f64>().sqrt();
    if norm_a == 0.0 || norm_b == 0.0 { return 0.0; }
    dot / (norm_a * norm_b)
}

fn permute(v: &TernaryVector, k: usize) -> TernaryVector {
    let d = v.dimension;
    let shift = k % d;
    let mut data = Vec::with_capacity(d);
    data.extend_from_slice(&v.data[shift..]);
    data.extend_from_slice(&v.data[..shift]);
    TernaryVector { dimension: d, data }
}

