fn prove_bind_inverse() -> ProofResult {
    let a = random_vector(PROOF_DIM, 42);
    let b = random_vector(PROOF_DIM, 137);
    let bound = bind(&a, &b);
    let recovered = unbind(&bound, &a);
    let sim = cosine_similarity(&recovered, &b);
    ProofResult { name: "bind_inverse".into(), passed: sim > 0.60, expected: 0.60, actual: sim, epsilon: SIMILARITY_EPSILON }
}

fn prove_bind_commutative() -> ProofResult {
    let a = random_vector(PROOF_DIM, 123);
    let b = random_vector(PROOF_DIM, 456);
    let ab = bind(&a, &b);
    let ba = bind(&b, &a);
    let ok = ab.data == ba.data;
    ProofResult { name: "bind_commutative".into(), passed: ok, expected: 1.0, actual: if ok { 1.0 } else { 0.0 }, epsilon: 0.0 }
}

fn prove_bind_self_identity() -> ProofResult {
    let a = random_vector(PROOF_DIM, 777);
    let self_bind = bind(&a, &a);
    let ok = self_bind.data.iter().zip(&a.data).all(|(&s, &a_i)| {
        s == if a_i == 0 { 0 } else { 1 }
    });
    ProofResult { name: "bind_self_identity".into(), passed: ok, expected: 1.0, actual: if ok { 1.0 } else { 0.0 }, epsilon: 0.0 }
}

fn prove_bind_associative() -> ProofResult {
    let a = random_vector(PROOF_DIM, 2024);
    let b = random_vector(PROOF_DIM, 2025);
    let c = random_vector(PROOF_DIM, 2026);
    let ab_c = bind(&bind(&a, &b), &c);
    let a_bc = bind(&a, &bind(&b, &c));
    let ok = ab_c.data == a_bc.data;
    ProofResult { name: "bind_associative".into(), passed: ok, expected: 1.0, actual: if ok { 1.0 } else { 0.0 }, epsilon: 0.0 }
}

fn prove_bundle_convergence() -> ProofResult {
    let a = random_vector(PROOF_DIM, 1001);
    let b = random_vector(PROOF_DIM, 1002);
    let c = random_vector(PROOF_DIM, 1003);
    let bundled = bundle3(&a, &b, &c);
    let sim_a = cosine_similarity(&bundled, &a);
    let sim_b = cosine_similarity(&bundled, &b);
    let sim_c = cosine_similarity(&bundled, &c);
    let ok = sim_a > 0.15 && sim_b > 0.15 && sim_c > 0.15;
    let min_sim = sim_a.min(sim_b).min(sim_c);
    ProofResult { name: "bundle_convergence".into(), passed: ok, expected: 0.15, actual: min_sim, epsilon: 0.05 }
}

fn prove_orthogonality() -> ProofResult {
    let trials = 50;
    let total: f64 = (0..trials).map(|t| {
        let a = random_vector(PROOF_DIM, 10000 + t * 2);
        let b = random_vector(PROOF_DIM, 10001 + t * 2);
        cosine_similarity(&a, &b).abs()
    }).sum();
    let avg = total / trials as f64;
    ProofResult { name: "orthogonality".into(), passed: avg < 0.15, expected: 0.15, actual: avg, epsilon: 0.05 }
}

fn prove_permute_cycle() -> ProofResult {
    let dim = 256;
    let a = random_vector(dim, 55);
    let k = 17;
    let p1 = permute(&a, k);
    let p2 = permute(&p1, dim - k);
    let sim = cosine_similarity(&p2, &a);
    ProofResult { name: "permute_cycle".into(), passed: (sim - 1.0).abs() < 0.001, expected: 1.0, actual: sim, epsilon: 0.001 }
}

fn prove_similarity_bounds() -> ProofResult {
    let ok = (0..PROOF_TRIALS).all(|t| {
        let a = random_vector(512, 20000 + t * 2);
        let b = random_vector(512, 20001 + t * 2);
        let sim = cosine_similarity(&a, &b);
        sim >= -1.001 && sim <= 1.001
    });
    ProofResult { name: "similarity_bounds".into(), passed: ok, expected: 1.0, actual: if ok { 1.0 } else { 0.0 }, epsilon: 0.001 }
}

fn prove_trinity_identity() -> ProofResult {
    let trinity = PHI_SQ + 1.0 / PHI_SQ;
    let ok = (trinity - 3.0).abs() < 1e-12;
    ProofResult { name: "trinity_identity".into(), passed: ok, expected: 3.0, actual: trinity, epsilon: 1e-12 }
}

fn prove_information_density() -> ProofResult {
    let log2_3 = 3.0_f64.log2();
    let compression = 32.0 / log2_3;
    let ok = (log2_3 - 1.58496).abs() < 0.001 && compression > 20.0;
    ProofResult { name: "information_density".into(), passed: ok, expected: 1.58496, actual: log2_3, epsilon: 0.001 }
}

